import numpy as np
import random
from typing import List, Dict

def calculate_tardiness(schedule: List[int], jobs: List[Dict]) -> int:
    """Calculate total tardiness for a given schedule."""
    job_map = {job['id']: job for job in jobs}
    current_time = 0
    total_tardiness = 0
    for job_id in schedule:
        job = job_map[job_id]
        current_time += job['processing_time']
        tardiness = max(0, current_time - job['due_date'])
        total_tardiness += tardiness
    return total_tardiness

def generate_initial_population(pop_size: int, num_jobs: int) -> np.ndarray:
    """Generate initial population of permutations."""
    population = []
    for _ in range(pop_size):
        individual = np.random.permutation(num_jobs)
        population.append(individual)
    return np.array(population)

def apply_swaps(individual: np.ndarray, swaps: List[tuple]) -> np.ndarray:
    """Apply a series of swaps to an individual."""
    individual = individual.copy()
    for i, j in swaps:
        individual[i], individual[j] = individual[j], individual[i]
    return individual

def discrete_differential_evolution(jobs: List[Dict], pop_size: int = 50, max_iter: int = 1000, F: float = 0.8, CR: float = 0.9) -> List[int]:
    """Discrete Differential Evolution for job scheduling."""
    num_jobs = len(jobs)
    if num_jobs == 0:
        return []

    population = generate_initial_population(pop_size, num_jobs)
    fitness = np.array([calculate_tardiness(individual.tolist(), jobs) for individual in population])
    best_fitness = np.min(fitness)
    best_individual = population[np.argmin(fitness)].copy()

    for iteration in range(max_iter):
        for i in range(pop_size):
            # Select three distinct individuals
            candidates = [idx for idx in range(pop_size) if idx != i]
            a, b, c = random.sample(candidates, 3)

            # Generate donor vector (difference between b and c as swaps)
            donor = population[a].copy()
            swaps = []
            for idx in range(num_jobs):
                if random.random() < F:
                    # Safeguard against empty array in np.where
                    target_positions = np.where(population[b] == population[c][idx])[0]
                    if len(target_positions) > 0:
                        swaps.append((idx, target_positions[0]))
            donor = apply_swaps(donor, swaps)

            # Crossover
            trial = population[i].copy()
            for idx in range(num_jobs):
                if random.random() < CR:
                    trial[idx] = donor[idx]

            # Evaluate trial
            trial_fitness = calculate_tardiness(trial.tolist(), jobs)
            if trial_fitness < fitness[i]:
                population[i] = trial
                fitness[i] = trial_fitness
                if trial_fitness < best_fitness:
                    best_fitness = trial_fitness
                    best_individual = trial.copy()

    # Convert best individual to job IDs
    job_ids = [jobs[i]['id'] for i in best_individual]
    return job_ids

def schedule(jobs: List[Dict]) -> List[int]:
    """Schedule jobs to minimize total tardiness using Discrete Differential Evolution."""
    return discrete_differential_evolution(jobs)
